ALGORITHM FetchWordFromMemory
INPUT: memoryAddress, targetRegister
OUTPUT: data in targetRegister

VARIABLES:
 MAR // Memory Address Register
 MDR // Memory Data Register
 MemRead // Control signal (boolean)
 DataBus // Temporary storage for data transfer
 Memory // Array representing main memory

BEGIN
 // Step 1: Place address in MAR
 MAR <- memoryAddress

 // Step 2: Issue Read Command
 MemRead <- TRUE

 // Step 3: Memory Unit Operation
 // Memory hardware decodes address and retrieves word
 DataBus <- Memory[MAR]

 // Step 4: Data Transfer to MDR
 MDR <- DataBus

 // Step 5: Transfer data to target CPU register
 targetRegister <- MDR

 // Deactivate read signal
 MemRead <- FALSE

 // Return success status
 RETURN SUCCESS
END

#include <stdio.h>
#include <stdint.h>
#include <string.h>

/* Define word size for the system */
#define WORD_SIZE uint32_t
#define MEMORY_SIZE 65536

/* CPU Registers structure simulating MAR, MDR, and general registers */
typedef struct {
 uint32_t MAR; // Memory Address Register
 uint32_t MDR; // Memory Data Register
 uint32_t PC; // Program Counter
 uint32_t R1; // General purpose register 1
 uint32_t R2; // General purpose register 2
 int MemRead; // Control signal: 1 = active, 0 = inactive
} CPU;

/* Memory structure representing main RAM */
typedef struct {
 uint32_t data[MEMORY_SIZE];
} Memory;

/* Initialize memory with some test values */
void init_memory(Memory *mem) {
 memset(mem->data, 0, sizeof(mem->data));

 // Store test data at specific addresses
 mem->data[0x2050] = 0xABCD1234;
 mem->data[0x2051] = 0xDEADBEEF;
 mem->data[0x2052] = 0xCAFEBABE;
}

/* Simulate reading from memory (returns data at address) */
uint32_t memory_read(Memory *mem, uint32_t address) {
 if (address < MEMORY_SIZE) {
 return mem->data[address];
 }
 return 0;
}

/*
 * Fetch a word from memory into a CPU register
 * Implements the 5-step fetch sequence:
 * 1. Load address into MAR
 * 2. Activate MemRead signal
 * 3. Memory unit reads data
 * 4. Load data into MDR
 * 5. Transfer to target register
 */
void fetch_word(CPU *cpu, Memory *mem, uint32_t address, uint32_t *target_reg) {
 printf("=== Fetching word from memory address 0x%04X ===\n", address);

 /* Step 1: Place address in MAR */
 cpu->MAR = address;
 printf("Step 1: Address 0x%04X loaded into MAR\n", cpu->MAR);

 /* Step 2: Issue Read Command - activate MemRead */
 cpu->MemRead = 1;
 printf("Step 2: MemRead control signal activated (MemRead=1)\n");

 /* Step 3 & 4: Memory access - data goes to MDR via data bus */
 cpu->MDR = memory_read(mem, cpu->MAR);
 printf("Step 3-4: Memory unit reads MAR, data = 0x%08X loaded into MDR\n", cpu->MDR);

 /* Step 5: Transfer data from MDR to target register */
 *target_reg = cpu->MDR;
 printf("Step 5: Data transferred from MDR to target register\n");

 /* Deactivate read signal */
 cpu->MemRead = 0;
 printf("Step 6: MemRead signal deactivated\n");

 printf("Result: Target register now holds value 0x%08X\n\n", *target_reg);
}

int main() {
 /* Initialize CPU and Memory */
 CPU cpu = {0};
 Memory memory;

 init_memory(&memory);

 printf("Memory initialized with test data\n");
 printf("Address 0x2050: 0x%08X\n", memory.data[0x2050]);
 printf("Address 0x2051: 0x%08X\n", memory.data[0x2051]);
 printf("\n");

 /* Fetch word at address 0x2050 into R1 */
 fetch_word(&cpu, &memory, 0x2050, &cpu.R1);

 /* Fetch word at address 0x2051 into R2 */
 fetch_word(&cpu, &memory, 0x2051, &cpu.R2);

 /* Display final CPU state */
 printf("=== Final CPU State ===\n");
 printf("MAR: 0x%08X\n", cpu.MAR);
 printf("MDR: 0x%08X\n", cpu.MDR);
 printf("R1: 0x%08X (fetched from address 0x2050)\n", cpu.R1);
 printf("R2: 0x%08X (fetched from address 0x2051)\n", cpu.R2);
 printf("MemRead: %d\n", cpu.MemRead);

 return 0;
}
